#! /bin/bash
DB_LITE_PG_FILE=$1
DB_LITE_ES_DIRECTORY=$2
docker cp $DB_LITE_PG_FILE pg:/dblite_pg.dump
docker exec -ti pg dropdb -U inaturalist inaturalist_development
docker exec -ti pg createdb -U inaturalist inaturalist_development
docker exec -ti pg pg_restore -U inaturalist -v --no-owner --no-acl -d inaturalist_development /dblite_pg.dump

docker cp  $DB_LITE_ES_DIRECTORY es:/snapshots/

docker exec -ti -u root es chown -R elasticsearch:root /snapshots

curl -X PUT "http://localhost:9200/_cluster/settings" \
  -H "Content-Type: application/json" \
  -d '{"transient": { "action.destructive_requires_name": false }}'

curl -X DELETE "http://localhost:9200/_all"

curl -sS -X PUT "http://localhost:9200/_snapshot/dblite_es_20260225" \
  -H "Content-Type: application/json" \
  -d '{"type": "fs", "settings": {"location": "/snapshots/dblite_es_20260225", "compress": true}}'

curl -fsS -X POST "http://localhost:9200/_snapshot/dblite_es_20260225/dblite_es_snapshot/_restore?wait_for_completion=true" \
  -H "Content-Type: application/json" \
  -d '{"include_global_state":false,"rename_pattern":"production_(.+)","rename_replacement":"development_$1"}'

